-- BATCH 5: HEALTH & EDUCATION (5 templates)

INSERT INTO dream_templates (slug, title, category, description, emoji, color, big_wins, small_wins, daily_activities, onboarding_questions, alternative_futures) VALUES
('doctor','Dokter Profesional','Health & Education','Jadilah dokter profesional yang menyembuhkan dan menyelamatkan nyawa. Dedikasi, empati, dan ilmu medis adalah senjata utamamu dalam melawan penyakit.','🩺','#10B981','["Diterima di fakultas kedokteran","Lulus koas dengan predikat memuaskan","Mendapatkan STR (Surat Tanda Registrasi)","Mulai praktik di rumah sakit","Menangani 1000+ pasien","Spesialisasi bidang tertentu","Buka klinik sendiri"]'::jsonb,'["Cek jadwal praktik","Konsultasi dengan pasien","Review rekam medis","Belajar jurnal medis terbaru","Koordinasi dengan perawat","Pendidikan medis lanjutan","Istirahat + manajemen stres"]'::jsonb,'[{"dimension": "Praktik Klinis", "items": ["Periksa pasien rawat jalan", "Konsultasi diagnosis", "Tulis resep obat"]},{"dimension": "Medis", "items": ["Review hasil lab", "Analisis rekam medis", "Rencana perawatan"]},{"dimension": "Belajar", "items": ["Baca jurnal medis", "Update pedoman klinis", "Webinar medis"]},{"dimension": "Administrasi", "items": ["Lengkapi dokumen medis", "Koordinasi rujukan", "Manajemen jadwal"]},{"dimension": "Kolaborasi", "items": ["Diskusi kasus dengan kolega", "Briefing tim medis", "Supervisi koas"]},{"dimension": "Self-care", "items": ["Stretching sela kerja", "Manajemen stres", "Tidur cukup + istirahat"]}]'::jsonb,'[{"question": "Spesialisasi dokter yang diminati?", "type": "single_select", "options": [{"label": "Umum", "value": "umum"}, {"label": "Bedah", "value": "bedah"}, {"label": "Anak", "value": "anak"}, {"label": "Dalam", "value": "dalam"}]},{"question": "Level pendidikan saat ini?", "type": "single_select", "options": [{"label": "Mahasiswa kedokteran", "value": "mahasiswa"}, {"label": "Koas", "value": "koas"}, {"label": "Dokter umum", "value": "dokter-umum"}, {"label": "Residen", "value": "residen"}]},{"question": "Target utama karir medis?", "type": "single_select", "options": [{"label": "Spesialis", "value": "spesialis"}, {"label": "Klinik sendiri", "value": "klinik-sendiri"}, {"label": "Riset medis", "value": "riset-medis"}, {"label": "Dosen FK", "value": "dosen-fk"}]},{"question": "Nilai terpenting sebagai dokter?", "type": "single_select", "options": [{"label": "Empati", "value": "empati"}, {"label": "Ketelitian", "value": "ketelitian"}, {"label": "Dedikasi", "value": "dedikasi"}, {"label": "Integritas", "value": "integritas"}]}]'::jsonb,'[{"title": "Dosen Fakultas Kedokteran", "description": "Mendidik calon dokter baru di universitas ternama.", "slug": "alternative-medical-lecturer"},{"title": "Peneliti Medis", "description": "Melakukan riset untuk penemuan pengobatan baru.", "slug": "alternative-medical-researcher"},{"title": "Konsultan Kesehatan", "description": "Memberikan konsultasi kesehatan di industri wellness.", "slug": "alternative-health-consultant"}]'::jsonb),
('psychologist','Psikolog Profesional','Health & Education','Jadilah psikolog profesional yang membantu orang menemukan kesejahteraan mental. Empati, ilmu psikologi, dan kemampuan mendengar adalah kekuatanmu.','🧠','#8B5CF6','["Diterima di fakultas psikologi","Lulus S1 Psikologi","Mendapat izin praktik","Menangani 100+ klien","Spesialisasi bidang psikologi","Publikasi paper/jurnal","Buka praktik sendiri"]'::jsonb,'["Review jadwal konseling","Sesi terapi dengan klien","Catat progress klien","Supervisi kasus","Baca riset psikologi","Self-care rutin","Kembangkan materi terapi"]'::jsonb,'[{"dimension": "Konseling", "items": ["Sesi terapi individu", "Terapi kelompok", "Asesmen psikologis"]},{"dimension": "Administrasi", "items": ["Catat progress note", "Review rekam klien", "Buat laporan asesmen"]},{"dimension": "Belajar", "items": ["Baca jurnal psikologi", "Update pendekatan terapi", "Workshop profesional"]},{"dimension": "Supervisi", "items": ["Konsultasi kasus", "Peer supervision", "Mentoring intern"]},{"dimension": "Self-care", "items": ["Mindfulness practice", "Journaling + refleksi", "Batasan kerja sehat"]},{"dimension": "Edukasi", "items": ["Buat konten mental health", "Webinar edukasi", "Buku/artikel psikologi"]}]'::jsonb,'[{"question": "Bidang psikologi favorit?", "type": "single_select", "options": [{"label": "Klinis", "value": "klinis"}, {"label": "Pendidikan", "value": "pendidikan"}, {"label": "Industri", "value": "industri"}, {"label": "Anak", "value": "anak"}]},{"question": "Level pendidikan psikologi?", "type": "single_select", "options": [{"label": "Mahasiswa", "value": "mahasiswa"}, {"label": "S1 Psikologi", "value": "s1"}, {"label": "Profesi Psikolog", "value": "profesi"}, {"label": "S2/S3", "value": "s2-s3"}]},{"question": "Target utama karir psikologi?", "type": "single_select", "options": [{"label": "Praktik pribadi", "value": "praktik-pribadi"}, {"label": "Rumah sakit", "value": "rumah-sakit"}, {"label": "HR/Industrial", "value": "hr"}, {"label": "Akademisi", "value": "akademisi"}]},{"question": "Pendekatan terapi favorit?", "type": "single_select", "options": [{"label": "CBT", "value": "cbt"}, {"label": "Psikodinamik", "value": "psikodinamik"}, {"label": "Humanistik", "value": "humanistik"}, {"label": "Mindfulness", "value": "mindfulness"}]}]'::jsonb,'[{"title": "HR Psychologist", "description": "Menerapkan psikologi di dunia industri dan organisasi.", "slug": "alternative-hr-psychologist"},{"title": "Academic Researcher", "description": "Melakukan riset psikologi untuk pengembangan ilmu.", "slug": "alternative-psychology-researcher"},{"title": "Life Coach", "description": "Membantu klien mencapai potensi maksimal dalam hidup.", "slug": "alternative-life-coach"}]'::jsonb),
('dentist','Dokter Gigi Profesional','Health & Education','Jadilah dokter gigi profesional yang menjaga senyum indah pasien. Keahlian, ketelitian, dan teknologi dental adalah alatmu memberikan layanan gigi terbaik.','🦷','#06B6D4','["Diterima di fakultas kedokteran gigi","Lulus profesi dokter gigi","Mendapat STR","Praktik di klinik gigi","Menangani 500+ pasien","Spesialisasi kedokteran gigi","Buka klinik gigi sendiri"]'::jsonb,'["Cek jadwal pasien","Periksa gigi pasien","Tindakan perawatan gigi","Sterilisasi alat","Edukasi pasien","Belajar teknik baru","Manajemen klinik"]'::jsonb,'[{"dimension": "Praktik", "items": ["Periksa kondisi gigi pasien", "Tindakan scaling/restorasi", "Konsultasi perawatan"]},{"dimension": "Klinis", "items": ["Review rontgen", "Rencana perawatan", "Tindakan operasi kecil"]},{"dimension": "Sterilisasi", "items": ["Sterilisasi alat dental", "Cek kebersihan klinik", "Manajemen limbah medis"]},{"dimension": "Edukasi", "items": ["Edukasi oral hygiene", "Brosur perawatan gigi", "Kampanye kesehatan gigi"]},{"dimension": "Belajar", "items": ["Baca jurnal dental", "Update teknik baru", "Workshop kedokteran gigi"]},{"dimension": "Bisnis", "items": ["Manajemen inventaris", "Follow up pasien", "Promosi klinik"]}]'::jsonb,'[{"question": "Spesialisasi gigi yang diminati?", "type": "single_select", "options": [{"label": "Umum", "value": "umum"}, {"label": "Ortodonti", "value": "ortodonti"}, {"label": "Bedah mulut", "value": "bedah-mulut"}, {"label": "Estetika gigi", "value": "estetika"}]},{"question": "Level pendidikan saat ini?", "type": "single_select", "options": [{"label": "Mahasiswa FKG", "value": "mahasiswa"}, {"label": "Koas", "value": "koas"}, {"label": "Dokter gigi", "value": "dokter-gigi"}, {"label": "Spesialis", "value": "spesialis"}]},{"question": "Target utama karir dokter gigi?", "type": "single_select", "options": [{"label": "Klinik sendiri", "value": "klinik-sendiri"}, {"label": "Spesialis", "value": "spesialis"}, {"label": "Rumah sakit", "value": "rumah-sakit"}, {"label": "Dosen", "value": "dosen"}]},{"question": "Layanan gigi favorit?", "type": "single_select", "options": [{"label": "Scaling", "value": "scaling"}, {"label": "Tambal gigi", "value": "tambal"}, {"label": "Behel", "value": "behel"}, {"label": "Pemutihan gigi", "value": "pemutihan"}]}]'::jsonb,'[{"title": "Dosen Kedokteran Gigi", "description": "Mengajar dan mendidik calon dokter gigi di universitas.", "slug": "alternative-dental-lecturer"},{"title": "Peneliti Kesehatan Gigi", "description": "Riset inovasi perawatan dan material gigi.", "slug": "alternative-dental-researcher"},{"title": "CEO Dental Chain", "description": "Membangun jaringan klinik gigi berskala nasional.", "slug": "alternative-dental-chain-ceo"}]'::jsonb),
('pharmacist','Apoteker Profesional','Health & Education','Jadilah apoteker profesional yang memastikan obat yang tepat untuk pasien. Pengetahuan farmasi dan ketelitian adalah kunci keselamatan pasien.','💊','#EC4899','["Diterima di fakultas farmasi","Lulus profesi apoteker","Mendapat SIPA","Praktik di apotek","Mengelola 1000+ resep","Spesialisasi farmasi klinik","Buka apotek sendiri"]'::jsonb,'["Cek stok obat harian","Layani resep pasien","Konsultasi obat","Edukasi pasien","Update regulasi BPOM","Belajar obat baru","Manajemen apotek"]'::jsonb,'[{"dimension": "Pelayanan", "items": ["Layani resep pasien", "Konsultasi interaksi obat", "Edukasi cara minum obat"]},{"dimension": "Manajemen", "items": ["Cek stok obat", "Order dari distributor", "Rotasi obat kadaluarsa"]},{"dimension": "Regulasi", "items": ["Update aturan BPOM", "Cek izin edar obat", "Dokumentasi narkotika"]},{"dimension": "Klinis", "items": ["Review resep dokter", "Konsultasi dosis", "Monitoring efek samping"]},{"dimension": "Belajar", "items": ["Baca jurnal farmasi", "Webinar obat terbaru", "Update DPHO"]},{"dimension": "Bisnis", "items": ["Manajemen keuangan apotek", "Promosi produk sehat", "Pelayanan ekstra"]}]'::jsonb,'[{"question": "Bidang farmasi favorit?", "type": "single_select", "options": [{"label": "Farmasi klinik", "value": "klinik"}, {"label": "Industri", "value": "industri"}, {"label": "Komunitas", "value": "komunitas"}, {"label": "Regulasi", "value": "regulasi"}]},{"question": "Level pendidikan farmasi?", "type": "single_select", "options": [{"label": "Mahasiswa", "value": "mahasiswa"}, {"label": "S1 Farmasi", "value": "s1"}, {"label": "Apoteker", "value": "apoteker"}, {"label": "Spesialis", "value": "spesialis"}]},{"question": "Target utama karir farmasi?", "type": "single_select", "options": [{"label": "Apotek sendiri", "value": "apotek-sendiri"}, {"label": "Rumah sakit", "value": "rumah-sakit"}, {"label": "Industri farmasi", "value": "industri-farmasi"}, {"label": "BPOM", "value": "bpom"}]},{"question": "Aspek terpenting sebagai apoteker?", "type": "single_select", "options": [{"label": "Ketelitian", "value": "ketelitian"}, {"label": "Pengetahuan", "value": "pengetahuan"}, {"label": "Komunikasi", "value": "komunikasi"}, {"label": "Integritas", "value": "integritas"}]}]'::jsonb,'[{"title": "Industrial Pharmacist", "description": "Berkarir di industri farmasi dalam R&D dan produksi obat.", "slug": "alternative-industrial-pharmacist"},{"title": "Regulatory Affairs", "description": "Mengurus registrasi dan regulasi produk farmasi.", "slug": "alternative-regulatory-affairs"},{"title": "Clinical Researcher", "description": "Terlibat dalam clinical trial pengembangan obat baru.", "slug": "alternative-clinical-researcher"}]'::jsonb),
('teacher','Guru Profesional','Health & Education','Jadilah guru profesional yang mencerdaskan generasi bangsa. Dedikasi, kesabaran, dan inovasi dalam mengajar adalah kunci mencetak masa depan cerah.','📚','#F59E0B','["Menyelesaikan pendidikan keguruan","Mendapat sertifikasi guru","Mengajar kelas pertama","Memenangkan lomba inovasi mengajar","Membimbing siswa juara","Mendapat penghargaan guru","Menjadi kepala sekolah"]'::jsonb,'["Persiapan materi ajar","Mengajar di kelas","Koreksi tugas siswa","Rapat dengan guru lain","Bimbingan siswa","Pelatihan guru","Evaluasi pembelajaran"]'::jsonb,'[{"dimension": "Persiapan", "items": ["Buat RPP harian", "Siapkan materi ajar", "Buat media pembelajaran"]},{"dimension": "Mengajar", "items": ["Mengajar di kelas", "Diskusi interaktif", "Praktikum/proyek"]},{"dimension": "Evaluasi", "items": ["Koreksi tugas + ujian", "Input nilai", "Analisis hasil belajar"]},{"dimension": "Bimbingan", "items": ["Konseling siswa", "Bimbingan belajar", "Ekstrakurikuler"]},{"dimension": "Profesional", "items": ["Ikut pelatihan guru", "Baca jurnal pendidikan", "Workshop kurikulum"]},{"dimension": "Administrasi", "items": ["Rapat dewan guru", "Laporan akademik", "Komunikasi orang tua"]}]'::jsonb,'[{"question": "Bidang/Bidang studi favorit?", "type": "single_select", "options": [{"label": "Matematika", "value": "matematika"}, {"label": "Bahasa", "value": "bahasa"}, {"label": "IPA", "value": "ipa"}, {"label": "IPS", "value": "ips"}]},{"question": "Level pendidikan yang diajar?", "type": "single_select", "options": [{"label": "SD", "value": "sd"}, {"label": "SMP", "value": "smp"}, {"label": "SMA/SMK", "value": "sma-smk"}, {"label": "Pendidikan tinggi", "value": "pt"}]},{"question": "Target utama karir guru?", "type": "single_select", "options": [{"label": "Guru bersertifikasi", "value": "sertifikasi"}, {"label": "Kepala sekolah", "value": "kepala-sekolah"}, {"label": "Pengawas", "value": "pengawas"}, {"label": "Dosen", "value": "dosen"}]},{"question": "Metode